import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.net.URI;
import java.net.URISyntaxException;
import java.util.List;
import java.util.Map;

@Service
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    public String handleWebhook(Map<String, Object> webhook) {
        List<String> urls = (List<String>) webhook.get("urls");
        for (String url : urls) {
            try {
                URI uri = new URI(url);
                if (!uri.getHost().startsWith("localhost")) {
                    HttpHeaders headers = new HttpHeaders();
                    headers.setContentType(MediaType.APPLICATION_JSON);
                    HttpEntity<String> entity = new HttpEntity<>(headers);

                    String response = restTemplate.exchange(uri, HttpMethod.GET, entity, String.class).getBody();

                    return response;
                }
            } catch (URISyntaxException e) {
                // Handle exception
            }
        }

        return null;
    }
}